CREATE TABLE IF NOT EXISTS n8n_chat_histories (id SERIAL PRIMARY KEY, session_id VARCHAR(255) NOT NULL, message JSONB NOT NULL);
CREATE INDEX IF NOT EXISTS idx_n8n_chat_histories_session ON n8n_chat_histories (session_id);
CREATE TABLE IF NOT EXISTS style_profile (chat_id BIGINT PRIMARY KEY, profile JSONB NOT NULL, refreshed_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS audit_log (id BIGSERIAL PRIMARY KEY, ts TIMESTAMPTZ NOT NULL DEFAULT now(), chat_id BIGINT, action TEXT, params JSONB, decision TEXT, intent_confidence NUMERIC);
ALTER TABLE audit_log ADD COLUMN IF NOT EXISTS chat_id BIGINT, ADD COLUMN IF NOT EXISTS params JSONB, ADD COLUMN IF NOT EXISTS decision TEXT, ADD COLUMN IF NOT EXISTS intent_confidence NUMERIC;
CREATE INDEX IF NOT EXISTS idx_audit_log_ts ON audit_log (ts);
CREATE INDEX IF NOT EXISTS idx_audit_log_chat_id ON audit_log (chat_id);
CREATE TABLE IF NOT EXISTS spend_log (id BIGSERIAL PRIMARY KEY, ts TIMESTAMPTZ NOT NULL DEFAULT now(), model TEXT, prompt_tokens INTEGER, completion_tokens INTEGER, cost_usd NUMERIC(10,6) NOT NULL DEFAULT 0);
ALTER TABLE spend_log ADD COLUMN IF NOT EXISTS prompt_tokens INTEGER, ADD COLUMN IF NOT EXISTS completion_tokens INTEGER;
CREATE INDEX IF NOT EXISTS idx_spend_log_ts ON spend_log (ts);
CREATE TABLE IF NOT EXISTS tg_updates_seen (update_id BIGINT PRIMARY KEY, seen_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS pending_actions (id BIGSERIAL PRIMARY KEY, created_at TIMESTAMPTZ NOT NULL DEFAULT now(), chat_id BIGINT, description TEXT, tool TEXT, args JSONB, status TEXT NOT NULL DEFAULT 'pending', resolved_at TIMESTAMPTZ);
CREATE INDEX IF NOT EXISTS idx_pending_actions_status ON pending_actions (status);
CREATE TABLE IF NOT EXISTS events (id BIGSERIAL PRIMARY KEY, ts TIMESTAMPTZ NOT NULL DEFAULT now(), chat_id BIGINT, action TEXT, dow INTEGER, hour INTEGER);
ALTER TABLE events ADD COLUMN IF NOT EXISTS chat_id BIGINT, ADD COLUMN IF NOT EXISTS action TEXT, ADD COLUMN IF NOT EXISTS dow INTEGER, ADD COLUMN IF NOT EXISTS hour INTEGER;
CREATE INDEX IF NOT EXISTS idx_events_ts ON events (ts);
SELECT table_name FROM information_schema.tables WHERE table_schema = 'public' AND table_name IN ('n8n_chat_histories','style_profile','audit_log','spend_log','tg_updates_seen','pending_actions','events') ORDER BY table_name;
